// Wedding Page - Version 2.0 - Fixed
import React, { useState, useEffect } from 'react';
import './WeddingPage.css';
import { ArrowUp, Church, Wine, Calendar, Phone, Mail, Heart, Navigation } from 'lucide-react';
import confetti from 'canvas-confetti';
import heroBg from "../images/hero-bg.jpeg";


const WeddingPage = () => {
  const [countdown, setCountdown] = useState({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [activeFaq, setActiveFaq] = useState(null);
  const [showCalendarOptions, setShowCalendarOptions] = useState(false);

// ScrollToTopButton – pływająca strzałka do góry
const ScrollToTopButton = () => {
  const [visible, setVisible] = React.useState(false);

  React.useEffect(() => {
    const handleScroll = () => {
      setVisible(window.scrollY > 300); // po przewinięciu 300px w dół pokaż przycisk
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' }); // płynne przewijanie na górę
  };

  return (
    <button
      className={`scroll-to-top ${visible ? 'visible' : ''}`}
      onClick={scrollToTop}
      aria-label="Scroll to top"
    >
      <ArrowUp size={24} />
    </button>
  );
};

  // Countdown Timer - do godziny 17:00 (ceremonia)
  useEffect(() => {
    const updateCountdown = () => {
      const weddingDate = new Date('2027-04-24T17:00:00');
      const now = new Date();
      const difference = weddingDate - now;

      if (difference > 0) {
        const days = Math.floor(difference / (1000 * 60 * 60 * 24));
        const hours = Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
        const minutes = Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60));
        const seconds = Math.floor((difference % (1000 * 60)) / 1000);
        setCountdown({ days, hours, minutes, seconds });
      } else {
        setCountdown({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      }
    };

    updateCountdown();
    const interval = setInterval(updateCountdown, 1000);
    return () => clearInterval(interval);
  }, []);

  // Scroll animations
  useEffect(() => {
    const observerOptions = {
      threshold: 0.1,
      rootMargin: '0px 0px -50px 0px'
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          entry.target.classList.add('visible');
        }
      });
    }, observerOptions);

    document.querySelectorAll('.wedding-section').forEach(section => {
      section.classList.add('fade-in');
      observer.observe(section);
    });

    return () => observer.disconnect();
  }, []);

  // Close calendar dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (showCalendarOptions && !e.target.closest('.save-date-wrapper')) {
        setShowCalendarOptions(false);
      }
    };
    document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [showCalendarOptions]);

  // Calendar integration
  const handleCalendarClick = (type) => {
    const eventDetails = {
      title: 'Ślub Kinga & Michał',
      description: 'Zapraszamy na nasz ślub!',
      location: 'Plac Konfederacji 55, 01-834 Warszawa',
      startDate: '20270424T170000',
      endDate: '20270425T050000'
    };

    if (type === 'google') {
      const googleUrl = new URL('https://calendar.google.com/calendar/render');
      googleUrl.searchParams.append('action', 'TEMPLATE');
      googleUrl.searchParams.append('text', eventDetails.title);
      googleUrl.searchParams.append('details', eventDetails.description);
      googleUrl.searchParams.append('location', eventDetails.location);
      googleUrl.searchParams.append('dates', `${eventDetails.startDate}/${eventDetails.endDate}`);
      window.open(googleUrl.toString(), '_blank');
    } else if (type === 'apple') {
      const icsContent = generateICS(eventDetails);
      const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
      const link = document.createElement('a');
      link.href = window.URL.createObjectURL(blob);
      link.download = 'slub-kinga-michal.ics';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
    setShowCalendarOptions(false);
  };

  const generateICS = (eventDetails) => {
    const now = new Date();
    const timestamp = now.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';

    const icsLines = [
      'BEGIN:VCALENDAR',
      'VERSION:2.0',
      'PRODID:-//Wedding Kinga & Michał//PL',
      'CALSCALE:GREGORIAN',
      'METHOD:PUBLISH',
      'X-WR-CALNAME:Ślub Kinga & Michał',
      'X-WR-TIMEZONE:Europe/Warsaw',
      'BEGIN:VTIMEZONE',
      'TZID:Europe/Warsaw',
      'BEGIN:STANDARD',
      'DTSTART:19701025T030000',
      'TZOFFSETFROM:+0200',
      'TZOFFSETTO:+0100',
      'RRULE:FREQ=YEARLY;BYMONTH=10;BYDAY=-1SU',
      'END:STANDARD',
      'BEGIN:DAYLIGHT',
      'DTSTART:19700329T020000',
      'TZOFFSETFROM:+0100',
      'TZOFFSETTO:+0200',
      'RRULE:FREQ=YEARLY;BYMONTH=3;BYDAY=-1SU',
      'END:DAYLIGHT',
      'END:VTIMEZONE',
      'BEGIN:VEVENT',
      `UID:${timestamp}@wedding-kinga-michal`,
      `DTSTAMP:${timestamp}`,
      `DTSTART;TZID=Europe/Warsaw:${eventDetails.startDate}`,
      `DTEND;TZID=Europe/Warsaw:${eventDetails.endDate}`,
      `SUMMARY:${eventDetails.title}`,
      `DESCRIPTION:${eventDetails.description}`,
      `LOCATION:${eventDetails.location}`,
      'STATUS:CONFIRMED',
      'SEQUENCE:0',
      'TRANSP:OPAQUE',
      'BEGIN:VALARM',
      'TRIGGER:-P1D',
      'ACTION:DISPLAY',
      'DESCRIPTION:Przypomnienie: Jutro ślub Kingi i Michała!',
      'END:VALARM',
      'END:VEVENT',
      'END:VCALENDAR'
    ];
    return icsLines.join('\r\n');
  };

  const toggleFaq = (index) => {
    setActiveFaq(activeFaq === index ? null : index);
  };

  const faqData = [
    {
      question: 'Czy ceremonia i wesele odbywają się w tym samym miejscu?',
      answer: 'Nie. Ceremonia ślubna odbędzie się w kościele, natomiast przyjęcie weselne w sali weselnej. Dokładne adresy znajdziecie w zakładce "Jak do nas dojechać".'
    },
    {
      question: 'Czy będzie zapewniony transport między kościołem a salą?',
      answer: 'Nie organizujemy wspólnego transportu. Do sali można wygodnie dojechać samochodem lub skorzystać z usług przewozowych, takich jak Uber.'
