                  width="100%"
                  height="200"
                  style={{ border: 0 }}
                  allowFullScreen=""
                  loading="lazy"
                  referrerPolicy="no-referrer-when-downgrade"
                  title="Mapa - Ceremonia"
                ></iframe>
              </div>
              <a
                href="https://maps.app.goo.gl/WXoWZUWh7tDLzjoy7"
                target="_blank"
                rel="noopener noreferrer"
                className="btn btn-outline navigation-btn"
